#include "interface.h"
#include <vector>
#include <cstdint>
#include <deque>

namespace {

inline uint64_t mix(uint64_t hash, uint64_t value) {
    hash ^= value;
    hash *= 1099511628211ULL;
    return hash;
}

} // namespace

uint64_t sliding_window_max_hash(const std::vector<uint32_t>& values, int window, int iters) {
    const int n = static_cast<int>(values.size());
    if (window <= 0 || window > n) return 0;

    std::vector<uint32_t> maxima;
    maxima.reserve(n - window + 1);

    std::deque<int> dq;

    for (int i = 0; i < n; ++i) {
        while (!dq.empty() && dq.front() <= i - window)
            dq.pop_front();
        while (!dq.empty() && values[dq.back()] <= values[i])
            dq.pop_back();
        dq.push_back(i);
        if (i >= window - 1)
            maxima.push_back(values[dq.front()]);
    }

    uint64_t hash = 1469598103934665603ULL;
    for (int iter = 0; iter < iters; ++iter) {
        hash = 1469598103934665603ULL;
        for (uint32_t mx : maxima)
            hash = mix(hash, mx);
    }
    return hash;
}
